import{_ as a,c as e,o as m,b as t}from"./app.2f23aa5c.js";const y='{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 11","description":"","frontmatter":{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 11","subtitle":"\u0428\u0438\u0432\u0430 \u0441\u0443\u0442\u0440\u0430 \u0432\u0438\u043C\u0430\u0440\u0448\u0438\u043D\u0438. \u0413\u043B\u0430\u0432\u0430 1.","tags":"vim-1","sans":"\u0924\u094D\u0930\u093F\u0924\u092F\u092D\u094B\u0915\u094D\u0924\u093E \u0935\u0940\u0930\u0947\u0936\u0903","trans":"Tritayabhokt\u0101 v\u012Bre\u015Ba\u1E25","date":"2021-02-16T00:00:00.000Z"},"headers":[],"relativePath":"texts/shiva-sutra-vimarshini/1/11/index.md"}',r={},i=t('<div class="stanza"><a href="#s1.11" id="s1.11" class="num">1.11</a><div class="sans"><p>\u090F\u0935\u0902 \u0932\u094B\u0915\u092F\u094B\u0917\u094D\u092F\u0928\u0941\u0938\u093E\u0930\u0947\u0923 \u0935\u094D\u092F\u093E\u0916\u094D\u092F\u093E\u0924\u0947 \u091C\u093E\u0917\u0930\u093E\u0926\u093F\u0924\u094D\u0930\u092F\u0947 \u0936\u0915\u094D\u0924\u093F\u091A\u0915\u094D\u0930\u0938\u0928\u094D\u0927\u093E\u0928\u093E\u0926\u094D\u0935\u093F\u0936\u094D\u0935\u0938\u0902\u0939\u093E\u0930\u0947\u0923 \u092F\u0938\u094D\u092F \u0924\u0941\u0930\u094D\u092F\u093E\u092D\u094B\u0917\u092E\u092F\u0924\u094D\u0935\u092E\u092D\u0947\u0926\u0935\u094D\u092F\u093E\u092A\u094D\u0924\u094D\u092F\u093E\u0924\u094D\u092E\u0915\u0902 \u0938\u094D\u092B\u0941\u0930\u0924\u093F \u0938 \u0924\u0926\u094D\u0927\u093E\u0930\u093E\u0927\u093F\u0930\u094B\u0939\u0947\u0923 \u0924\u0941\u0930\u094D\u092F\u093E\u0924\u0940\u0924\u0902 \u092A\u0942\u0930\u094D\u0935\u094B\u0915\u094D\u0924\u0902 \u091A\u0948\u0924\u0928\u094D\u092F\u092E\u093E\u0935\u093F\u0936\u0928\u094D\u2014</p><blockquote><p><strong>\u0924\u094D\u0930\u093F\u0924\u092F\u092D\u094B\u0915\u094D\u0924\u093E \u0935\u0940\u0930\u0947\u0936\u0903\u0965\u0967\u0967\u0965</strong></p></blockquote><p>\u090F\u0924\u091C\u094D\u091C\u093E\u0917\u0930\u093E\u0926\u093F\u0924\u094D\u0930\u092F\u0902 \u0936\u0915\u094D\u0924\u093F\u091A\u0915\u094D\u0930\u093E\u0928\u0941\u0938\u0928\u094D\u0927\u093E\u0928\u092F\u0941\u0915\u094D\u0924\u094D\u092F\u093E \u0924\u0941\u0930\u094D\u092F\u093E\u0928\u0928\u094D\u0926\u093E\u091A\u094D\u091B\u0941\u0930\u093F\u0924\u0902 \u092F\u0938\u094D\u0924\u0924\u094D\u092A\u0930\u093E\u092E\u0930\u094D\u0936\u093E\u0928\u0941\u092A\u094D\u0930\u0935\u0947\u0936\u092A\u094D\u0930\u0915\u0930\u094D\u0937\u093E\u0926\u094D\u0935\u093F\u0917\u0932\u093F\u0924\u092D\u0947\u0926\u0938\u0902\u0938\u094D\u0915\u093E\u0930\u092E\u093E\u0928\u0928\u094D\u0926\u0930\u0938\u092A\u094D\u0930\u0935\u093E\u0939\u092E\u092F\u092E\u0947\u0935 \u092A\u0936\u094D\u092F\u0924\u093F \u0938 \u0924\u094D\u0930\u093F\u0924\u092F\u0938\u094D\u092F\u093E\u0938\u094D\u092F \u092D\u094B\u0915\u094D\u0924\u093E \u091A\u092E\u0924\u094D\u0915\u0930\u094D\u0924\u093E\u0964 \u0924\u0924 \u090F\u0935</p><blockquote><p>\u0924\u094D\u0930\u093F\u0937\u0941 \u0927\u093E\u092E\u0938\u0941 \u092F\u0926\u094D\u092D\u094B\u0917\u094D\u092F\u0902 \u092D\u094B\u0915\u094D\u0924\u093E \u092F\u0936\u094D\u091A \u092A\u094D\u0930\u0915\u0940\u0930\u094D\u0924\u093F\u0924\u0903 \u0935\u0947\u0926\u0948\u0924\u0926\u0941\u092D\u092F\u0902 \u092F\u0938\u094D\u0924\u0941 \u0938 \u092D\u0941\u091E\u094D\u091C\u093E\u0928\u094B \u0928 \u0932\u093F\u092A\u094D\u092F\u0924\u0947\u0965</p></blockquote><p>\u0907\u0924\u093F \u0928\u0940\u0924\u094D\u092F\u093E \u0928\u093F\u0903\u0938\u092A\u0924\u094D\u0928\u0938\u094D\u0935\u093E\u0924\u094D\u092E\u0938\u093E\u092E\u094D\u0930\u093E\u091C\u094D\u092F\u094B\u093D\u092F\u0902 \u092A\u0930\u092E\u093E\u0928\u0928\u094D\u0926\u092A\u0930\u093F\u092A\u0942\u0930\u094D\u0923\u094B \u092D\u0935\u092D\u0947\u0926\u0917\u094D\u0930\u0938\u0928\u092A\u094D\u0930\u0935\u0923\u093E\u0928\u093E\u0902 \u0935\u0940\u0930\u093E\u0923\u093E\u092E\u093F\u0928\u094D\u0926\u094D\u0930\u093F\u092F\u093E\u0923\u093E\u092E\u0940\u0936\u094D\u0935\u0930\u0903 \u0938\u094D\u0935\u093E\u092E\u0940 \u0936\u094D\u0930\u0940\u092E\u0928\u094D\u0925\u093E\u0928\u092D\u0948\u0930\u0935\u0938\u0924\u094D\u0924\u093E\u0928\u0941\u092A\u094D\u0930\u0935\u093F\u0937\u094D\u091F\u094B \u092E\u0939\u093E\u092E\u094D\u0928\u093E\u092F\u0947\u0937\u0942\u091A\u094D\u092F\u0924\u0947\u0964 \u092F\u0938\u094D\u0924\u094D\u0935\u0947\u0935\u0902\u0935\u093F\u0927\u094B \u0928 \u092D\u0935\u0924\u093F \u0938 \u091C\u093E\u0917\u0930\u093E\u0926\u094D\u092F\u0935\u0938\u094D\u0925\u093E\u092D\u093F\u0930\u094D\u092D\u0941\u091C\u094D\u092F\u092E\u093E\u0928\u094B \u0932\u094C\u0915\u093F\u0915\u0903 \u092A\u0936\u0941\u0930\u0947\u0935\u0964 \u092F\u094B\u0917\u094D\u092F\u092A\u0940\u092E\u093E\u0902 \u0927\u093E\u0930\u093E\u092E\u0928\u0927\u093F\u0930\u0942\u0922\u094B \u0928 \u0935\u0940\u0930\u0947\u0936\u094D\u0935\u0930\u094B\u093D\u092A\u093F \u0924\u0941 \u092E\u0942\u0922 \u090F\u0935\u0947\u0924\u094D\u092F\u0941\u0915\u094D\u0924\u0902 \u092D\u0935\u0924\u093F\u0964 \u090F\u0924\u091A\u094D\u091A</p><blockquote><p>\u092F\u094B\u0917\u0940 \u0938\u094D\u0935\u091A\u094D\u091B\u0928\u094D\u0926\u092F\u094B\u0917\u0947\u0928 \u0938\u094D\u0935\u091A\u094D\u091B\u0928\u094D\u0926\u0917\u0924\u093F\u091A\u093E\u0930\u093F\u0923\u093E \u0938 \u0938\u094D\u0935\u091A\u094D\u091B\u0928\u094D\u0926\u092A\u0926\u0947 \u092F\u0941\u0915\u094D\u0924\u0903 \u0938\u094D\u0935\u091A\u094D\u091B\u0928\u094D\u0926\u0938\u092E\u0924\u093E\u0902 \u0935\u094D\u0930\u091C\u0947\u0924\u094D\u0965</p></blockquote><p>\u0907\u0924\u094D\u092F\u093E\u0926\u093F\u0928\u093E \u0936\u094D\u0930\u0940\u0938\u094D\u0935\u091A\u094D\u091B\u0928\u094D\u0926\u093E\u0926\u093F\u0936\u093E\u0938\u094D\u0924\u094D\u0930\u0947\u0937\u0941 \u0935\u093F\u0924\u0924\u094D\u092F \u0926\u0930\u094D\u0936\u093F\u0924\u092E\u094D\u0964 \u0938\u094D\u092A\u0928\u094D\u0926\u0947\u093D\u092A\u093F</p><blockquote><p>\u0924\u0938\u094D\u092F\u094B\u092A\u0932\u092C\u094D\u0927\u093F\u0903 \u0938\u0924\u0924\u0902 \u0924\u094D\u0930\u093F\u092A\u0926\u093E\u0935\u094D\u092F\u092D\u093F\u091A\u093E\u0930\u093F\u0923\u0940\u0964</p></blockquote><p>\u0907\u0924\u093F \u0915\u093E\u0930\u093F\u0915\u092F\u093E \u0938\u0919\u094D\u0917\u0943\u0939\u0940\u0924\u092E\u0947\u0924\u0924\u094D\u0965\u0967\u0967\u0965</p></div><hr><div class="trans"><p>Eva\u1E41 lokayogyanus\u0101re\u1E47a vy\u0101khy\u0101te j\u0101gar\u0101ditraye \u015Bakticakrasandh\u0101n\u0101dvi\u015Bvasa\u1E41h\u0101re\u1E47a yasya tury\u0101bhogamayatvamabhedavy\u0101pty\u0101tmaka\u1E41 sphurati sa taddh\u0101r\u0101dhirohe\u1E47a tury\u0101t\u012Bta\u1E41 p\u016Brvokta\u1E41 caitanyam\u0101vi\u015Ban\u2014</p><blockquote><p><strong>Tritayabhokt\u0101 v\u012Bre\u015Ba\u1E25||11||</strong></p></blockquote><p>Etajj\u0101gar\u0101ditraya\u1E41 \u015Bakticakr\u0101nusandh\u0101nayukty\u0101 tury\u0101nand\u0101cchurita\u1E41 yastatpar\u0101mar\u015B\u0101nuprave\u015Baprakar\u1E63\u0101dvigalitabhedasa\u1E41sk\u0101ram\u0101nandarasaprav\u0101hamayameva pa\u015Byati sa tritayasy\u0101sya bhokt\u0101 camatkart\u0101| Tata eva</p><blockquote><p>Tri\u1E63u dh\u0101masu yadbhogya\u1E41 bhokt\u0101 ya\u015Bca prak\u012Brtita\u1E25 Vedaitadubhaya\u1E41 yastu sa bhu\xF1j\u0101no na lipyate||</p></blockquote><p>iti n\u012Bty\u0101 ni\u1E25sapatnasv\u0101tmas\u0101mr\u0101jyo&#39;ya\u1E41 param\u0101nandaparip\u016Br\u1E47o bhavabhedagrasanaprava\u1E47\u0101n\u0101\u1E41 v\u012Br\u0101\u1E47\u0101mindriy\u0101\u1E47\u0101m\u012B\u015Bvara\u1E25 sv\u0101m\u012B \u015Br\u012Bmanth\u0101nabhairavasatt\u0101nupravi\u1E63\u1E6Do mah\u0101mn\u0101ye\u1E63\u016Bcyate| Yastveva\u1E41vidho na bhavati sa j\u0101gar\u0101dyavasth\u0101bhirbhujyam\u0101no laukika\u1E25 pa\u015Bureva| Yogyap\u012Bm\u0101\u1E41 dh\u0101r\u0101manadhir\u016B\u1E0Dho na v\u012Bre\u015Bvaro&#39;pi tu m\u016B\u1E0Dha evetyukta\u1E41 bhavati| Etacca</p><blockquote><p>Yog\u012B svacchandayogena svacchandagatic\u0101ri\u1E47\u0101 Sa svacchandapade yukta\u1E25 svacchandasamat\u0101\u1E41 vrajet||</p></blockquote><p>ity\u0101din\u0101 \u015Br\u012Bsvacchand\u0101di\u015B\u0101stre\u1E63u vitatya dar\u015Bitam| Spande&#39;pi</p><blockquote><p>Tasyopalabdhi\u1E25 satata\u1E41 tripad\u0101vyabhic\u0101ri\u1E47\u012B|</p></blockquote><p>iti k\u0101rikay\u0101 sa\u1E45g\u1E5Bh\u012Btametat||11||</p></div><hr><p>\u0422\u0430\u043A <em>(evam)</em>, \u043E\u043D -- Yog\u012B-- <em>(sa\u1E25)</em>, \u0432 \u043A\u043E\u043C <em>(yasya)</em> \u0432\u043E\u0441\u0442\u043E\u0440\u0433 \u0438 \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u0435 <em>(\u0101bhoga)</em> \u0427\u0435\u0442\u0432\u0435\u0440\u0442\u044B\u043C \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435\u043C <em>(turya)</em>, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0438\u043C <em>(\u0101tmakam)</em> \u0438\u0437 \u043F\u0440\u043E\u043D\u0438\u043A\u043D\u043E\u0432\u0435\u043D\u0438\u044F <em>(vy\u0101pti)</em> \u0432 \u043D\u0435\u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u044C --\u0442.\u0435. \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u0435 \u0440\u0430\u0437\u043B\u0438\u0447\u0438\u0439-- <em>(abheda)</em>, \u0441\u0438\u044F\u0435\u0442 <em>(sphurati)</em> \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0438\u0441\u0447\u0435\u0437\u043D\u043E\u0432\u0435\u043D\u0438\u044E <em>(sa\u1E41h\u0101re\u1E47a)</em> \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439 <em>(vi\u015Bva)</em> \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0435\u0434\u0438\u043D\u0435\u043D\u0438\u044F <em>(sandh\u0101n\u0101t)</em> \u0441 \u0433\u0440\u0443\u043F\u043F\u043E\u0439 <em>(cakra)</em> \u0441\u0438\u043B <em>(\u015Bakti)</em> \u0432 \u0442\u0440\u0435\u0445 <em>(traye)</em> [\u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F\u0445] \u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F <em>(j\u0101gar\u0101)</em>, \u0438 \u0442.\u0434. <em>(\u0101di)</em>, \u0447\u0442\u043E \u0431\u044B\u043B\u043E \u043F\u043E\u0434\u0440\u043E\u0431\u043D\u043E \u0440\u0430\u0437\u044A\u044F\u0441\u043D\u0435\u043D\u043E <em>(vy\u0101khy\u0101te)</em> [\u0442\u0430\u043A\u0436\u0435] \u0432 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u0438 <em>(anus\u0101re\u1E47a)</em> \u0441 [\u043E\u043F\u044B\u0442\u043E\u043C] Yog\u012B <em>(yogi)</em> [\u0438] \u043E\u0431\u044B\u0447\u043D\u044B\u0445 \u043B\u044E\u0434\u0435\u0439 <em>(loka)</em><sup>1</sup>, \u0432\u0445\u043E\u0434\u0438\u0442 <em>(\u0101vi\u015Ban)</em> \u0432 \u0422\u0443\u0440\u044C\u044F\u0442\u0438\u0442\u0443 (Tury\u0101t\u012Bta) --\u0442.\u0435. \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0437\u0430 \u043F\u0440\u0435\u0434\u0435\u043B\u0430\u043C\u0438 \u0422\u0443\u0440\u044C\u0438 (Turya), \u0438\u043B\u0438 Tur\u012Bya (\u0427\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0433\u043E \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F)-- <em>(turya-at\u012Btam)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u043F\u0440\u0435\u0434\u0432\u0430\u0440\u0438\u0442\u0435\u043B\u044C\u043D\u043E \u0431\u044B\u043B\u0430 <em>(p\u016Brva)</em> \u043E\u043F\u0438\u0441\u0430\u043D\u0430 <em>(uktam)</em> \u043A\u0430\u043A \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435, \u043D\u0430\u0434\u0435\u043B\u0435\u043D\u043D\u043E\u0435 \u0410\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u043E\u0439 \u0421\u0432\u043E\u0431\u043E\u0434\u043E\u0439 \u0437\u043D\u0430\u0442\u044C \u0438 \u0434\u0435\u043B\u0430\u0442\u044C \u0432\u0441\u0435 <em>(caitanyam)</em>. [\u041E\u043D \u0432\u044A\u0435\u0437\u0436\u0430\u0435\u0442 \u0432 Tury\u0101t\u012Bta] \u0432\u0435\u0440\u0445\u043E\u043C, [\u043A\u0430\u043A \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F] <em>(adhirohe\u1E47a)</em>, \u043D\u0430 \u043F\u043E\u0442\u043E\u043A\u0435 <em>(dh\u0101r\u0101)</em> \u044D\u0442\u043E\u0433\u043E [\u0432\u043E\u0441\u0442\u043E\u0440\u0433\u0430 \u0438 \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u044F] <em>(tad)</em>\u2014</p><blockquote><p><strong>\u0422\u043E\u0442 \u0445\u043E\u0437\u044F\u0438\u043D <em>(\u012B\u015Ba\u1E25)</em> [\u0441\u0432\u043E\u0438\u0445] \u0447\u0443\u0432\u0441\u0442\u0432 <em>(v\u012Bra)</em>, \u043A\u0442\u043E \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0430\u044E\u0449\u0438\u043C\u0441\u044F [\u0432\u044B\u0448\u0435\u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u044B\u043C &quot;\u0101bhoga&quot;, \u0438\u043B\u0438 \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C \u0432\u043E\u0441\u0442\u043E\u0440\u0433\u043E\u043C] <em>(bhokt\u0101)</em> \u0432 \u0442\u0440\u0438\u0430\u0434\u0435 [\u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F, \u0441\u043D\u0430 \u0441\u043E \u0441\u043D\u043E\u0432\u0438\u0434\u0435\u043D\u0438\u044F\u043C\u0438 \u0438 \u0433\u043B\u0443\u0431\u043E\u043A\u043E\u0433\u043E \u0441\u043D\u0430] <em>(tritaya)</em>||11||</strong></p></blockquote><p>\u041E\u043D <em>(sa\u1E25)</em>, \u043A\u0442\u043E <em>(ya\u1E25)</em> \u0432\u0438\u0434\u0438\u0442 <em>(pa\u015Byati)</em> \u044D\u0442\u0443 <em>(etad)</em> \u0442\u0440\u0438\u0430\u0434\u0443 <em>(trayam)</em> \u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F <em>(j\u0101gar\u0101)</em>, \u0438 \u0442.\u0434. <em>(\u0101di)</em> \u043A\u0430\u043A \u0438\u0437\u043E\u0431\u0438\u043B\u0443\u044E\u0449\u0443\u044E <em>(\u0101cchuritam)</em> \u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u043E\u043C <em>(\u0101nanda)</em> \u0427\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0433\u043E \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F <em>(turya)</em> \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C <em>(yukty\u0101)</em> \u0435\u0434\u0438\u043D\u0435\u043D\u0438\u044F <em>(anusandh\u0101na)</em> \u0441 \u0433\u0440\u0443\u043F\u043F\u043E\u0439 <em>(cakra)</em> \u0441\u0438\u043B <em>(\u015Bakti)</em>, \u043A\u0430\u043A \u043D\u0435\u043F\u0440\u0435\u0440\u044B\u0432\u043D\u044B\u0439 \u043F\u043E\u0442\u043E\u043A <em>(prav\u0101ha-mayam eva)</em> \u0441\u043E\u043A\u0430 <em>(rasa)</em> \u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430 <em>(\u0101nanda)</em>, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u043C \u0432\u0441\u0435 \u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u044B\u0435 \u0432\u043F\u0435\u0447\u0430\u0442\u043B\u0435\u043D\u0438\u044F <em>(sa\u1E41sk\u0101ram)</em> \u0440\u0430\u0437\u043B\u0438\u0447\u0438\u0439 --\u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438-- <em>(bheda)</em> \u0431\u044B\u043B\u0438 \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u044B <em>(vigalita)</em> \u0447\u0435\u0440\u0435\u0437 \u0438\u043D\u0442\u0435\u043D\u0441\u0438\u0432\u043D\u043E\u0441\u0442\u044C <em>(prakar\u1E63\u0101t)</em> \u0432\u0445\u043E\u0436\u0434\u0435\u043D\u0438\u044F <em>(anuprave\u015Ba)</em> \u0432 \u043F\u0435\u0440\u0435\u0436\u0438\u0432\u0430\u043D\u0438\u0435 \u0438 \u0443\u0437\u043D\u0430\u0432\u0430\u043D\u0438\u0435 <em>(par\u0101mar\u015Ba)</em> \u044D\u0442\u043E\u0433\u043E [\u0427\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0433\u043E \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F] <em>(tad)</em>... [\u0442\u0430\u043A\u043E\u0439 \u0447\u0435\u043B\u043E\u0432\u0435\u043A \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0430\u044E\u0449\u0438\u043C\u0441\u044F <em>(bhokt\u0101)</em> \u044D\u0442\u043E\u0439 <em>(asya)</em> \u0442\u0440\u0438\u0430\u0434\u043E\u0439 <em>(tritayasya)</em>, [\u0430 \u0442\u0430\u043A\u0436\u0435] Camatk\u0101ra --\u0412\u043E\u0441\u0442\u043E\u0440\u0433\u043E\u043C \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F-- <em>(camatkart\u0101)</em>. [\u0414\u0440\u0443\u0433\u0438\u043C\u0438 \u0441\u043B\u043E\u0432\u0430\u043C\u0438, \u043E\u043D \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0430\u0435\u0442\u0441\u044F \u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u043E\u043C \u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u0432\u043E \u0432\u0441\u0435\u0439 \u0442\u0440\u0438\u0430\u0434\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0439]|</p><p>\u041F\u043E \u044D\u0442\u043E\u0439 \u043F\u0440\u0438\u0447\u0438\u043D\u0435 <em>(tatas eva)</em>:</p><blockquote><p>&quot;\u041E\u043D <em>(sa\u1E25)</em>, \u043A\u0442\u043E <em>(ya\u1E25)</em> \u043F\u043E\u0438\u0441\u0442\u0438\u043D\u0435 <em>(tu)</em> \u0437\u043D\u0430\u0435\u0442 <em>(veda)</em> \u044D\u0442\u043E\u0442 <em>(etad)</em> \u0434\u0443\u044D\u0442 <em>(ubhayam)</em>, \u0442.\u0435. [\u043F\u0440\u043E] \u043A\u043E\u0442\u043E\u0440\u044B\u0439 <em>(yad... ya\u1E25)</em> \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F [\u043A\u0430\u043A] <em>(prak\u012Brtita\u1E25)</em> \u043F\u0440\u043E \u043E\u0431\u044A\u0435\u043A\u0442 \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u044F --\u043F\u043E\u0437\u043D\u0430\u0432\u0430\u0435\u043C\u043E\u0435-- <em>(bhogyam)</em> \u0438 <em>(ca)</em> \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0430\u044E\u0449\u0435\u0433\u043E\u0441\u044F --\u043F\u043E\u0437\u043D\u0430\u044E\u0449\u0435\u0433\u043E-- <em>(bhokt\u0101)</em>, \u0432 \u0442\u0440\u0435\u0445 <em>(tri\u1E63u)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F\u0445 [\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F] <em>(dh\u0101masu)</em>, \u043D\u0435 <em>(na)</em> \u0437\u0430\u0433\u0440\u044F\u0437\u043D\u044F\u0435\u0442\u0441\u044F [\u0438\u043C\u0438] <em>(lipyate)</em> [\u0434\u0430\u0436\u0435 \u0435\u0441\u043B\u0438 \u043E\u043D \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C] \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0430\u044E\u0449\u0438\u043C\u0441\u044F --\u043F\u0435\u0440\u0435\u0436\u0438\u0432\u0430\u044E\u0449\u0438\u043C-- <em>(bhu\xF1j\u0101na\u1E25... iti)</em> [\u044D\u0442\u0438 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F]&quot;||</p></blockquote><p>\u0421\u043E\u0433\u043B\u0430\u0441\u043D\u043E [\u0432\u044B\u0448\u0435\u0438\u0437\u043B\u043E\u0436\u0435\u043D\u043D\u043E\u043C\u0443] \u043D\u0430\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0438\u044E <em>(n\u012Bty\u0101)</em>, \u044D\u0442\u043E [\u0432\u0435\u043B\u0438\u043A\u043E\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E] <em>(ayam)</em>, \u043D\u0430\u043F\u043E\u043B\u043D\u0435\u043D\u043D\u043E\u0435 <em>(parip\u016Br\u1E47a\u1E25)</em> \u0412\u044B\u0441\u0448\u0438\u043C <em>(parama)</em> \u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u043E\u043C <em>(\u0101nanda)</em>, [\u043F\u043E\u043B\u0443\u0447\u0430\u0435\u0442] \u043D\u0435\u043F\u0440\u0435\u0432\u0437\u043E\u0439\u0434\u0435\u043D\u043D\u043E\u0435 <em>(ni\u1E25sapatna)</em> \u0432\u043B\u0430\u0434\u044B\u0447\u0435\u0441\u0442\u0432\u043E \u043D\u0430\u0434 \u0441\u043E\u0431\u043E\u0439 <em>(sva-\u0101tma-s\u0101mr\u0101jya\u1E25)</em> [\u0438 \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F ] \u043F\u043E\u0432\u0435\u043B\u0438\u0442\u0435\u043B\u0435\u043C <em>(\u012B\u015Bvara\u1E25)</em>[\u0438] \u0433\u043E\u0441\u043F\u043E\u0434\u0438\u043D\u043E\u043C <em>(sv\u0101m\u012B)</em> [\u0441\u0432\u043E\u0438\u0445] \u0447\u0443\u0432\u0441\u0442\u0432 <em>(indriy\u0101\u1E47\u0101m)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 [\u0442\u0435\u043F\u0435\u0440\u044C] \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F v\u012Bra-s, \u0438\u043B\u0438 \u0433\u0435\u0440\u043E\u044F\u043C\u0438 <em>(v\u012Br\u0101\u1E47\u0101m)</em><sup>2</sup> , \u043D\u0430\u0446\u0435\u043B\u0435\u043D\u043D\u044B\u043C\u0438 \u043D\u0430 <em>(prava\u1E47\u0101n\u0101m)</em> \u043F\u043E\u0433\u043B\u043E\u0449\u0435\u043D\u0438\u0435 <em>(grasana)</em> \u0440\u0430\u0437\u043B\u0438\u0447\u0438\u0439 <em>(bheda)</em>, [\u0438\u043C\u0435\u044E\u0449\u0438\u0445 \u043C\u0435\u0441\u0442\u043E] \u0432 \u043C\u0438\u0440\u0441\u043A\u043E\u043C \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0438 <em>(bhava)</em>. \u0412 \u0432\u0435\u043B\u0438\u043A\u0438\u0445 <em>(mah\u0101)</em> \u0441\u0432\u044F\u0449\u0435\u043D\u043D\u044B\u0445 \u0442\u0435\u043A\u0441\u0442\u0430\u0445 --\u0101mn\u0101ya-s-- <em>(\u0101mn\u0101ye\u1E63u)</em><sup>3</sup> [\u043E \u0442\u0430\u043A\u043E\u043C \u0447\u0435\u043B\u043E\u0432\u0435\u043A\u0435] \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F <em>(ucyate)</em>, \u0447\u0442\u043E \u043E\u043D \u0432\u043E\u0448\u0435\u043B <em>(anupravi\u1E63\u1E6Da\u1E25)</em> \u0432 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0435 <em>(satt\u0101)</em> \u043F\u043E\u0447\u0442\u0435\u043D\u043D\u043E\u0433\u043E <em>(\u015Br\u012B)</em> Manth\u0101nabhairava <em>(manth\u0101na-bhairava)</em><sup>4</sup>|</p><p>\u041E\u0434\u043D\u0430\u043A\u043E <em>(tu)</em>, \u0442\u043E\u0442 <em>(sa\u1E25)</em>, \u043A\u0442\u043E <em>(ya\u1E25)</em> \u043D\u0435 \u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0441\u044F <em>(bhavati)</em> \u043A \u044D\u0442\u043E\u043C\u0443 \u0442\u0438\u043F\u0443 --\u0442.\u0435. \u0442\u043E\u0442, \u043A\u0442\u043E \u043D\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u043D\u044B\u043C-- <em>(eva\u1E41-vidha\u1E25)</em>, [\u0435\u0441\u0442\u044C] \u043F\u0440\u043E\u0441\u0442\u043E <em>(eva)</em> \u043E\u0431\u044B\u0447\u043D\u044B\u0439 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u0439 \u0438\u043D\u0434\u0438\u0432\u0438\u0434\u0443\u043C <em>(laukika\u1E25 pa\u015Bu\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0430\u0435\u0442\u0441\u044F <em>(bhujyam\u0101na\u1E25)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F\u043C\u0438 <em>(avasth\u0101bhi\u1E25)</em> \u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F <em>(j\u0101gar\u0101)</em>, \u0438 \u0442.\u0434. <em>(\u0101di)</em>|</p><p>\u0422\u043E\u0442 \u0436\u0435 <em>(api)</em> Yog\u012B <em>(yog\u012B)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u043D\u0435 \u0432\u044A\u0435\u0437\u0436\u0430\u0435\u0442, [\u0442\u0430\u043A \u0441\u043A\u0430\u0437\u0430\u0442\u044C,] <em>(anadhir\u016B\u1E0Dha\u1E25)</em> \u043D\u0430 \u044D\u0442\u043E\u043C <em>(im\u0101m)</em> \u043F\u043E\u0442\u043E\u043A\u0435 [\u0432\u043E\u0441\u0442\u043E\u0440\u0433\u0430 \u0438 \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u044F --\u0101bhoga--] <em>(dh\u0101r\u0101m)</em>, [\u043D\u0435 \u043C\u043E\u0436\u0435\u0442 \u0441\u0442\u0430\u0442\u044C] \u043F\u043E\u0432\u0435\u043B\u0438\u0442\u0435\u043B\u0435\u043C <em>(\u012B\u015Bvara\u1E25)</em> [\u0441\u0432\u043E\u0438\u0445] \u0447\u0443\u0432\u0441\u0442\u0432 <em>(v\u012Bra)</em>, \u0430 <em>(api tu)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0432\u0441\u0435\u0433\u043E \u043B\u0438\u0448\u044C <em>(eva)</em> \u0441\u043C\u0443\u0449\u0435\u043D\u043D\u044B\u043C \u0438 \u0441\u0431\u0438\u0442\u044B\u043C \u0441 \u0442\u043E\u043B\u043A\u0443 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u043C <em>(m\u016B\u1E0Dha\u1E25)</em>. \u0412\u043E\u0442, \u0447\u0442\u043E \u0431\u044B\u043B\u043E \u0441\u043A\u0430\u0437\u0430\u043D\u043E [\u043E \u043D\u0435\u043C] <em>(iti uktam bhavati)</em>|</p><p>\u0418 <em>(ca)</em> \u044D\u0442\u043E <em>(etad)</em> [\u0436\u0435 \u0441\u0430\u043C\u043E\u0435] \u0431\u044B\u043B\u043E \u043F\u043E\u043A\u0430\u0437\u0430\u043D\u043E <em>(dar\u015Bitam)</em> \u0432 \u0421\u0432\u044F\u0449\u0435\u043D\u043D\u044B\u0445 \u041F\u0438\u0441\u0430\u043D\u0438\u044F\u0445 <em>(\u015B\u0101stre\u1E63u)</em>, [\u0442\u0430\u043A\u0438\u0445 \u043A\u0430\u043A] \u043E\u0441\u0432\u044F\u0449\u0435\u043D\u043D\u043E\u0439 \u0432\u0435\u043A\u0430\u043C\u0438 <em>(\u015Br\u012B)</em> Svacchandatantra <em>(svacchanda)</em>, \u0438 \u0442.\u0434. <em>(\u0101di)</em>, \u043F\u043E\u0441\u043B\u0435 \u043F\u043E\u0434\u0440\u043E\u0431\u043D\u043E\u0433\u043E \u043E\u0431\u044A\u044F\u0441\u043D\u0435\u043D\u0438\u044F [\u044D\u0442\u043E\u0433\u043E] <em>(vitatya)</em> [\u0432 \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0438\u0445 \u0438 \u0434\u0440\u0443\u0433\u0438\u0445 \u0441\u0442\u0440\u043E\u0444\u0430\u0445]:</p><blockquote><p>&quot;\u0422\u043E\u0442 <em>(sa\u1E25)</em> Yog\u012B <em>(yog\u012B)</em>, \u043A\u0442\u043E \u0436\u0438\u0432\u0435\u0442 <em>(c\u0101ri\u1E47\u0101)</em> \u0432 \u0443\u0441\u043B\u043E\u0432\u0438\u044F\u0445 <em>(gati)</em> \u043D\u0435\u0437\u0430\u0432\u0438\u0441\u0438\u043C\u043E\u0433\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F --\u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u043D\u043E\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E-- <em>(svacchanda)</em> \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C Svacchandayoga --\u0442\u0438\u043F \u0419\u043E\u0433\u0438, \u043F\u0440\u0435\u043F\u043E\u0434\u0430\u0432\u0430\u0435\u043C\u043E\u0439 \u0432 Svacchandatantra-- <em>(svacchanda-yogena)</em>, \u0431\u0443\u0434\u0443\u0447\u0438 \u0435\u0434\u0438\u043D\u044B\u043C <em>(yukta\u1E25)</em> \u0441 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435\u043C <em>(pade)</em> Svacchanda <em>(svacchanda)</em><sup>5</sup>, \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442 <em>(vrajet)</em> \u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u0430 <em>(samat\u0101)</em> \u0441 Svacchanda <em>(svacchanda... iti \u0101din\u0101)</em>&quot;| [\u0421\u043C. VII, 260 \u0432 Svacchandatantra]</p></blockquote><p>\u0412 Spandak\u0101rik\u0101-s _(spande)_\u0442\u0430\u043A\u0436\u0435 <em>(api)</em>, \u044D\u0442\u043E [\u0436\u0435 \u0441\u0430\u043C\u043E\u0435 \u0443\u0447\u0435\u043D\u0438\u0435] <em>(etad)</em> \u0431\u044B\u043B\u043E \u043E\u0431\u043E\u0431\u0449\u0435\u043D\u043E <em>(sa\u1E45g\u1E5Bh\u012Btam)</em> [\u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0435\u0439 \u0447\u0430\u0441\u0442\u044C\u044E] k\u0101rik\u0101 --\u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0430-- <em>(k\u0101rikay\u0101)</em>:</p><blockquote><p>&quot;[\u041F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043F\u0440\u043E\u0431\u0443\u0436\u0434\u0435\u043D\u043D\u044B\u0439 \u0432\u0441\u0435\u0433\u0434\u0430 \u0438] \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E <em>(satatam)</em> \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442 <em>(upalabdhi\u1E25)</em> \u042D\u0442\u043E --\u0442.\u0435. \u0412\u044B\u0441\u0448\u0435\u0435 \u042F-- <em>(tasya)</em>, [\u0438 \u044D\u0442\u043E \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u0435 \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u042F] \u043F\u0440\u0438\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u0435\u0442 <em>(avyabhic\u0101ri\u1E47\u012B)</em> [\u0432\u043E \u0432\u0441\u0435\u0445] \u0442\u0440\u0435\u0445 <em>(tri)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F\u0445 [\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F] <em>(pada... iti)</em>...&quot; [\u0421\u043C. Spandak\u0101rik\u0101-s I, 17]</p></blockquote><p>||11||</p><hr><ol><li><p>\u0427\u0438\u0442\u0430\u0439\u0442\u0435 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0438 \u043D\u0430 \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u044B 8, 9 \u0438 10 \u044D\u0442\u043E\u0433\u043E \u0436\u0435 \u0440\u0430\u0437\u0434\u0435\u043B\u0430.</p></li><li><p>\u041F\u043E\u0434\u043E\u0431\u043D\u043E \u043F\u043E\u0434\u043B\u0438\u043D\u043D\u044B\u043C \u0433\u0435\u0440\u043E\u044F\u043C, \u044D\u0442\u0438 \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0435 \u0447\u0443\u0432\u0441\u0442\u0432\u0430 \u043F\u0440\u043E\u0441\u0432\u0435\u0442\u043B\u0435\u043D\u043D\u043E\u0433\u043E \u0447\u0435\u043B\u043E\u0432\u0435\u043A\u0430 \u0432\u0441\u0435\u0433\u0434\u0430 \u043F\u0440\u0435\u0441\u043B\u0435\u0434\u0443\u044E\u0442 \u0432\u044B\u0441\u0448\u0443\u044E \u0446\u0435\u043B\u044C \u0436\u0438\u0437\u043D\u0438 \u0438 \u0431\u043B\u0430\u0433\u043E\u043F\u043E\u043B\u0443\u0447\u0438\u044F \u0432\u0441\u0435\u0445. \u041E\u043D\u0438 \u0443\u0436\u0435 \u043D\u0435 \u043F\u0440\u043E\u0441\u0442\u043E &quot;indriya-s&quot;, \u0438\u043B\u0438 &quot;\u0447\u0443\u0432\u0441\u0442\u0432\u0430&quot;, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0432\u0441\u0435 \u0432\u0440\u0435\u043C\u044F \u043C\u0443\u0447\u0430\u044E\u0442 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u0443\u044E \u043B\u0438\u0447\u043D\u043E\u0441\u0442\u044C, \u0430 \u0432\u044B\u0441\u0448\u0438\u0435 \u0441\u0438\u043B\u044B, \u0441\u043B\u0443\u0436\u0430\u0449\u0438\u0435 \u044D\u0442\u043E\u043C\u0443 \u0432\u044B\u0441\u043E\u043A\u043E \u0434\u0443\u0445\u043E\u0432\u043D\u043E\u043C\u0443 \u0447\u0435\u043B\u043E\u0432\u0435\u043A\u0443.</p></li><li><p>\u041D\u0430\u0441\u0447\u0438\u0442\u044B\u0432\u0430\u0435\u0442\u0441\u044F 64 \u0432\u0435\u043B\u0438\u043A\u0438\u0445 \u0441\u0432\u044F\u0449\u0435\u043D\u043D\u044B\u0445 \u0442\u0435\u043A\u0441\u0442\u0430, \u0430\u0432\u0442\u043E\u0440\u0441\u0442\u0432\u043E \u043A\u043E\u0442\u043E\u0440\u044B\u0445 \u043D\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0447\u0435\u043B\u043E\u0432\u0435\u0447\u0435\u0441\u043A\u0438\u043C. \u042D\u0442\u0430 \u0433\u0440\u0443\u043F\u043F\u0430 \u044F\u0432\u043B\u0435\u043D\u043D\u044B\u0445 \u041F\u0438\u0441\u0430\u043D\u0438\u0439 \u0442\u0430\u043A\u0436\u0435 \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u0430 \u043A\u0430\u043A Bhairava\u015B\u0101stra-s (\u041F\u0438\u0441\u0430\u043D\u0438\u044F Bhairava). Bhairava - \u044D\u0442\u043E, \u043A\u043E\u043D\u0435\u0447\u043D\u043E, \u0412\u044B\u0441\u0448\u0435\u0435 \u042F.</p></li><li><p>\u042D\u0442\u043E \u044D\u043F\u0438\u0442\u0435\u0442 \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u042F, \u0431\u0443\u043A\u0432\u0430\u043B\u044C\u043D\u043E \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot;Bhairava - \u044D\u0442\u043E \u0442\u043E\u0442, \u043A\u0442\u043E \u0432\u0437\u0431\u0438\u0432\u0430\u0435\u0442, \u0441\u043E\u0442\u0440\u044F\u0441\u0430\u0435\u0442 \u0438 \u043F\u0435\u0440\u0435\u043C\u0435\u0448\u0438\u0432\u0430\u0435\u0442 (\u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0443\u044E)&quot;, \u0432 \u0442\u043E\u043C \u0441\u043C\u044B\u0441\u043B\u0435, \u0447\u0442\u043E \u041E\u043D \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442, \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0435\u0442 \u0438 \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u044F\u0435\u0442 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0443\u044E \u0432 \u0421\u0432\u043E\u0435\u043C \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u043C \u042F \u0441\u043D\u043E\u0432\u0430 \u0438 \u0441\u043D\u043E\u0432\u0430.</p></li><li><p>\u0422\u0435\u0440\u043C\u0438\u043D &quot;Svacchanda&quot; \u0431\u0443\u043A\u0432\u0430\u043B\u044C\u043D\u043E \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 \u0438 &quot;\u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F \u0441\u0432\u043E\u0431\u043E\u0434\u043D\u0430\u044F \u0432\u043E\u043B\u044F&quot;, \u0438 &quot;\u043D\u0435\u0437\u0430\u0432\u0438\u0441\u0438\u043C\u044B\u0439&quot;. \u0412 \u044D\u0442\u043E\u043C \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0435, Svacchanda - \u044D\u0442\u043E \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u043D\u043E\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E, \u0442.\u0435. \u0421\u0430\u043C \u015Aiva, \u043D\u043E \u0432 \u0442\u043E \u0436\u0435 \u0432\u0440\u0435\u043C\u044F\u044D\u0442\u043E \u0442\u0430\u043A\u0436\u0435 \u0415\u0433\u043E \u0410\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u0430\u044F \u0421\u0432\u043E\u0431\u043E\u0434\u043D\u0430\u044F \u0412\u043E\u043B\u044F \u0437\u043D\u0430\u0442\u044C \u0438 \u0434\u0435\u043B\u0430\u0442\u044C \u0432\u0441\u0435. \u041F\u0440\u0438\u043C\u0435\u043D\u044F\u044F \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0439 \u0430\u0444\u0444\u0438\u043A\u0441 (\u0421\u043C. \u0410\u0444\u0444\u0438\u043A\u0441\u044B), \u0432 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u0435 \u043F\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0441\u043B\u043E\u0432\u043E &quot;Sv\u0101cchandya&quot;. \u042D\u0442\u043E \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot;\u0441\u0432\u043E\u0431\u043E\u0434\u0430&quot;. \u041A\u043E\u0440\u043E\u0447\u0435 \u0433\u043E\u0432\u043E\u0440\u044F, \u044D\u0442\u043E \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 Svacchanda, \u0438\u043B\u0438 \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u043D\u043E\u0433\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430. \u0418 \u0434\u0430, Sv\u0101cchandya - \u044D\u0442\u043E \u0441\u0438\u043D\u043E\u043D\u0438\u043C \u0421\u0432\u0430\u0442\u0430\u043D\u0442\u0440\u0438\u0438 (Sv\u0101tantrya) (\u0410\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u043E\u0439 \u0421\u0432\u043E\u0431\u043E\u0434\u044B \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u042F).</p></li></ol></div>',1),p=[i];function o(s,n,u,h,c,v){return m(),e("div",null,p)}var k=a(r,[["render",o]]);export{y as __pageData,k as default};
